// ─── 安全数据提取（不要动） ───────────────────────
const data = (() => {
  const raw = ctx.data;
  if (Array.isArray(raw)) return raw;
  if (raw && Array.isArray(raw.objects)) return raw.objects;
  if (raw && Array.isArray(raw.data)) return raw.data;
  return [];
})();

if (data.length === 0) {
  return { title: { text: '暂无数据', left: 'center', top: 'center', textStyle: { color: '#999', fontSize: 14 } } };
}

// ─── 业务逻辑 ──────────────────────────────────────
const months = data.map(d => d.month);
return {
  title: { text: '月度生产产出', left: 'center', textStyle: { fontSize: 14 } },
  tooltip: { trigger: 'axis' },
  legend: { bottom: 0 },
  xAxis: { type: 'category', data: months },
  yAxis: [{ type: 'value', name: '数量' }, { type: 'value', name: '良品率%', max: 100 }],
  series: [
    { name: '完工', type: 'bar', data: data.map(d => parseInt(d.completed||0)), itemStyle: { color: '#52c41a', borderRadius: [4,4,0,0] } },
    { name: '不良', type: 'bar', data: data.map(d => parseInt(d.defects||0)), itemStyle: { color: '#ff4d4f', borderRadius: [4,4,0,0] } },
    { name: '良品率', type: 'line', yAxisIndex: 1, data: data.map(d => parseFloat(d.yield_rate||0)), smooth: true, lineStyle: { color: '#722ed1' }, itemStyle: { color: '#722ed1' } }
  ]
};
